const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

const express = require('express');
const projectsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.get('/:projectId', async (req, res) => {
  try {
    const project = await projectsService.getProject(req.params.projectId);
    if (!project) {
      return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
    }
    res.json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Failed to get project');
  }
});

router.post('/', async (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_PAYLOAD', 'Name is required');
  }
  try {
    const __existingProject = await projectsService.getProjectByName(name);
  if (__existingProject) return sendError(res, 409, 'PROJECT_DUPLICATE', 'Project already exists');
  const project = await projectsService.createProject(name);
    res.status(201).json({ project });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Failed to create project');
  }
});

module.exports = router;

const express = require('express');
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.patch('/:taskId', async (req, res) => {
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Status must be either todo or done');
  }
  try {
    const task = await tasksService.updateTask(req.params.taskId, status);
    if (!task) {
      return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
    }
    res.json({ task });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Failed to update task');
  }
});

router.get('/', async (req, res) => {
  const { status } = req.query;
  try {
    const tasks = await tasksService.getTasks(status);
    res.json({ tasks });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Failed to get tasks');
  }
});

module.exports = router;

const { randomUUID } = require('../../lib/id');

let tasksStore = {};

const updateTask = async (taskId, status) => {
  if (!tasksStore[taskId]) {
    return null;
  }
  tasksStore[taskId].status = status;
  return tasksStore[taskId];
};

const getTasks = async (status) => {
  const tasks = Object.values(tasksStore);
  if (status) {
    return tasks.filter(task => task.status === status);
  }
  return tasks;
};

module.exports = { updateTask, getTasks };

const express = require('express');
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_PAYLOAD', 'UserId and role are required');
  }
  try {
    const member = await membersService.addMember(req.params.projectId, userId, role);
    if (!member) return sendError(res, 409, 'MEMBER_DUPLICATE', 'Member already exists');
  res.status(201).json({ member });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Failed to add member');
  }
});

module.exports = router;

const { randomUUID } = require('../../lib/id');

let membersStore = {};

const addMember = async (projectId, userId, role) => {
  const memberId = randomUUID();
  if (!membersStore[projectId]) {
    membersStore[projectId] = [];
  }
  membersStore[projectId].push({ id: memberId, projectId, userId, role });
  return { id: memberId, projectId, userId, role };
};

module.exports = { addMember };

const express = require('express');
const commentsService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', async (req, res) => {
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_PAYLOAD', 'Message is required');
  }
  try {
    const comment = await commentsService.createComment(req.params.taskId, message);
    res.status(201).json({ comment });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Failed to create comment');
  }
});

router.get('/', async (req, res) => {
  try {
    const comments = await commentsService.getComments(req.params.taskId);
    res.json({ comments });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'Failed to get comments');
  }
});

module.exports = router;

const { randomUUID } = require('../../lib/id');

let commentsStore = {};

const createComment = async (taskId, message) => {
  const commentId = randomUUID();
  if (!commentsStore[taskId]) {
    commentsStore[taskId] = [];
  }
  commentsStore[taskId].push({ id: commentId, taskId, message });
  return { id: commentId, taskId, message };
};

const getComments = async (taskId) => {
  if (!commentsStore[taskId]) {
    return [];
  }
  return commentsStore[taskId];
};

module.exports = { createComment, getComments };

const sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};

module.exports = { sendError };
